# ─────────────────────────────────────────────
# スタイル設定
# ──────────��──────────────────────────────────
HEADER_FILL = PatternFill(start_color="1F4E79", end_color="1F4E79", fill_type="solid")
HEADER_FONT = Font(name="Meiryo", bold=True, color="FFFFFF", size=11)
ODD_ROW_FILL = PatternFill(start_color="F2F7FF", end_color="F2F7FF", fill_type="solid")
EVEN_ROW_FILL = PatternFill(start_color="FFFFFF", end_color="FFFFFF", fill_type="solid")
BODY_FONT = Font(name="Meiryo", size=10)
BORDER_SIDE = Side(style="thin", color="BFBFBF")
THIN_BORDER = Border(left=BORDER_SIDE, right=BORDER_SIDE, top=BORDER_SIDE, bottom=BORDER_SIDE)

HEADERS = ["No.", "会社名", "サイトURL", "住所", "売上高", "上場・未上場", "事業内容"]
COL_WIDTHS = [5, 32, 42, 40, 24, 32, 60]

TAB_CONFIGS = [
    ("介護事業者", CARE_COMPANIES, "2ECC71"),
    ("不動産事業者", REAL_ESTATE_COMPANIES, "E74C3C"),
    ("観光事業者", TOURISM_COMPANIES, "F39C12"),
    ("システム開発会社", IT_COMPANIES, "3498DB"),
    ("新規システム", NEW_IT_COMPANIES, "8E44AD"),
    ("新規運送", TRANSPORT_IT_COMPANIES, "E67E22"),
]

# ─────────────────────────────────────────────
# ワークブック生成
# ─────────────────────────────────────────────
wb = openpyxl.Workbook()
wb.remove(wb.active)

for sheet_name, companies, tab_color in TAB_CONFIGS:
    ws = wb.create_sheet(title=sheet_name)
    ws.sheet_properties.tabColor = tab_color

    for col, (header, width) in enumerate(zip(HEADERS, COL_WIDTHS), 1):
        cell = ws.cell(row=1, column=col, value=header)
        cell.font = HEADER_FONT
        cell.fill = HEADER_FILL
        cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        cell.border = THIN_BORDER
        ws.column_dimensions[get_column_letter(col)].width = width
    ws.row_dimensions[1].height = 25

    for row_idx, company in enumerate(companies, 2):
        fill = ODD_ROW_FILL if row_idx % 2 == 0 else EVEN_ROW_FILL
        row_data = [row_idx - 1] + list(company)
        for col, value in enumerate(row_data, 1):
            cell = ws.cell(row=row_idx, column=col, value=value)
            cell.font = BODY_FONT
            cell.fill = fill
            cell.border = THIN_BORDER
            cell.alignment = Alignment(vertical="top", wrap_text=True)
            if col == 1:
                cell.alignment = Alignment(horizontal="center", vertical="top")
        ws.row_dimensions[row_idx].height = 42

    ws.freeze_panes = "B2"

    last_row = len(companies) + 2
    ws.cell(row=last_row, column=1, value=f"計 {len(companies)} 社")
    ws.cell(row=last_row, column=1).font = Font(name="Meiryo", bold=True, size=10)

