print(f"  Kanko:         {len(TOURISM_COMPANIES):3d}")
print(f"  IT:            {len(IT_COMPANIES):3d}")
print(f"  新規システム:  {len(NEW_IT_COMPANIES):3d}")
print(f"  新規運送:      {len(TRANSPORT_IT_COMPANIES):3d}")
print(f"  Total:         {len(CARE_COMPANIES)+len(REAL_ESTATE_COMPANIES)+len(TOURISM_COMPANIES)+len(IT_COMPANIES)+len(NEW_IT_COMPANIES)+len(TRANSPORT_IT_COMPANIES):3d}")
